func verifyMTLSPeer(ctx context.Context) error {
	p, ok := peer.FromContext(ctx)
	if !ok {
		return fmt.Errorf("no peer information found")
	}

	tlsInfo, ok := p.AuthInfo.(credentials.TLSInfo)
	if !ok {
		return fmt.Errorf("no TLS credentials found - mTLS required")
	}

	if len(tlsInfo.State.VerifiedChains) == 0 {
		return fmt.Errorf("no verified certificate chains - client certificate required")
	}

	return nil
}

func extractAndValidateToken(ctx context.Context, store *TokenStore) (*ServiceToken, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, fmt.Errorf("no metadata provided")
	}

	authHeaders := md.Get("authorization")
	if len(authHeaders) == 0 {
		return nil, fmt.Errorf("no authorization header")
	}

	token := authHeaders[0]
	if strings.HasPrefix(token, "Bearer ") {
		token = strings.TrimPrefix(token, "Bearer ")
	} else {
		return nil, fmt.Errorf("authorization header must use Bearer scheme")
	}

	return store.ValidateToken(token)
}

